import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    colors = [c for c in np.unique(grid) if c != 0]
    if not colors:
        return grid

    # Find connected components for non-zero colors (4-neighborhood)
    visited = np.zeros((h, w), dtype=bool)
    comps = []

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 or visited[r, c]:
                continue
            color = grid[r, c]
            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                        visited[nx, ny] = True
                        stack.append((nx, ny))
            comps.append((color, cells))

    if not comps:
        return grid

    # Choose the upper component as anchor: smallest top row, then smallest left
    comps.sort(key=lambda item: (min(r for r, _ in item[1]), min(c for _, c in item[1])))
    color, cells = comps[0]

    # Build corrected shape from the anchor component only
    rows = [r for r, _ in cells]
    cols = [c for _, c in cells]
    top, left = min(rows), min(cols)
    bottom, right = max(rows), max(cols)
    comp_set = set(cells)

    out = np.zeros_like(grid)

    # Keep the anchor component, but fill one-step left where a diagonal progression suggests it
    for r in range(top, bottom + 1):
        for c in range(left, right + 1):
            if (r, c) in comp_set:
                out[r, c] = color

    # Extend left by one step for cells that are part of a down-right diagonal chain
    for r in range(top, bottom + 1):
        for c in range(left + 1, right + 1):
            if (r, c) in comp_set and (r - 1, c - 1) in comp_set and out[r, c - 1] == 0:
                out[r, c - 1] = color

    # Also fill any missing cells on rows where the pattern forms a horizontal run with a gap
    # bounded by occupied cells, but only within the anchor component's bounding box.
    for r in range(top, bottom + 1):
        row_cells = [c for rr, c in cells if rr == r]
        if len(row_cells) >= 2:
            mn, mx = min(row_cells), max(row_cells)
            for c in range(mn, mx + 1):
                if out[r, c] == 0 and any((r, c2) in comp_set for c2 in (c - 1, c + 1) if left <= c2 <= right):
                    # Only fill if this cell is directly between occupied cells or completes a leftward extension
                    if ((r, c + 1) in comp_set) or ((r, c - 1) in comp_set):
                        out[r, c] = color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    colors = [c for c in np.unique(grid) if c != 0]
    if not colors:
        return grid

    # Find connected components for each color using 4-neighborhood
    def components_of_color(color):
        visited = np.zeros((h, w), dtype=bool)
        comps = []
        for r in range(h):
            for c in range(w):
                if grid[r, c] == color and not visited[r, c]:
                    stack = [(r, c)]
                    visited[r, c] = True
                    cells = []
                    while stack:
                        x, y = stack.pop()
                        cells.append((x, y))
                        for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                                visited[nx, ny] = True
                                stack.append((nx, ny))
                    comps.append(cells)
        return comps

    # Choose the upper component as anchor among the two repeated copies
    best_color = None
    best_pair = None
    best_top = h + 1

    for color in colors:
        comps = components_of_color(color)
        if len(comps) < 2:
            continue
        comps = sorted(comps, key=lambda cells: min(r for r, _ in cells))
        upper = comps[0]
        lower = comps[1]
        top_upper = min(r for r, _ in upper)
        if top_upper < best_top:
            best_top = top_upper
            best_color = color
            best_pair = (upper, lower)

    if best_color is None:
        return grid

    upper, lower = best_pair

    # Build corrected output from the upper component only
    out = np.zeros_like(grid)

    upper_set = set(upper)
    rows = sorted(set(r for r, _ in upper))
    cols = sorted(set(c for _, c in upper))

    # Keep the outline of the upper pattern
    for r, c in upper:
        out[r, c] = best_color

    # Fill missing cells by extending one step left along diagonal progressions
    # Detect cells that have a down-right continuation in the upper component
    for r, c in upper:
        if (r + 1, c + 1) in upper_set and c - 1 >= 0:
            out[r, c - 1] = best_color

    # Also fill any gaps inside the bounding box that are implied by row-wise diagonal shift
    # by aligning each row to the leftmost occupied cell of the upper component.
    row_to_cols = {}
    for r, c in upper:
        row_to_cols.setdefault(r, []).append(c)

    for r, cs in row_to_cols.items():
        cs = sorted(cs)
        if len(cs) >= 2:
            # If the row has a gap between consecutive occupied cells and the next row shifts right,
            # fill the left-adjacent cell to complete the diagonal progression.
            for i in range(len(cs) - 1):
                if cs[i + 1] - cs[i] > 1 and cs[i] - 1 >= 0:
                    out[r, cs[i] - 1] = best_color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    rows = grid.shape[0]

    # Split into horizontal sections separated by all-zero rows
    zero_rows = np.all(grid == 0, axis=1)
    sections = []
    start = None
    for i in range(rows):
        if not zero_rows[i] and start is None:
            start = i
        if start is not None and (i == rows - 1 or zero_rows[i + 1]):
            sections.append(grid[start:i + 1])
            start = None

    # Determine dominant nonzero color for each section
    dominant_colors = []
    for sec in sections:
        vals, counts = np.unique(sec[sec != 0], return_counts=True)
        if len(vals) == 0:
            dominant_colors.append(None)
        else:
            dominant_colors.append(vals[np.argmax(counts)])

    # Find the section whose dominant color differs from the others
    target_idx = 0
    if len(dominant_colors) > 1:
        for i, c in enumerate(dominant_colors):
            others = [x for j, x in enumerate(dominant_colors) if j != i]
            if all(o == others[0] for o in others) and c != others[0]:
                target_idx = i
                break
        else:
            # Fallback: choose the section with a unique dominant color count
            for i, c in enumerate(dominant_colors):
                if dominant_colors.count(c) == 1:
                    target_idx = i
                    break

    target = sections[target_idx]
    out = np.where(target != 0, 3, 0)
    return out

