def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    rows, cols = grid.shape

    # Find horizontal bands separated by all-zero rows
    zero_rows = np.all(grid == 0, axis=1)
    bands = []
    start = None
    for i in range(rows):
        if not zero_rows[i] and start is None:
            start = i
        if (zero_rows[i] or i == rows - 1) and start is not None:
            end = i if zero_rows[i] else i + 1
            bands.append((start, end))
            start = None

    # If no bands found, return empty-like
    if not bands:
        return np.zeros((0, 0), dtype=int)

    # Determine dominant nonzero color for each band
    band_info = []
    for s, e in bands:
        sub = grid[s:e]
        vals = sub[sub != 0]
        if vals.size == 0:
            continue
        colors, counts = np.unique(vals, return_counts=True)
        dominant = colors[np.argmax(counts)]
        band_info.append((s, e, dominant, sub.shape))

    if not band_info:
        return np.zeros((0, 0), dtype=int)

    # Find the band whose dominant color is unique
    dom_colors = [info[2] for info in band_info]
    unique_color = None
    for c in dom_colors:
        if dom_colors.count(c) == 1:
            unique_color = c
            break
    if unique_color is None:
        unique_color = dom_colors[0]

    # Extract the unique-color band and convert its nonzero cells to 3
    for s, e, dom, shape in band_info:
        if dom == unique_color:
            out = grid[s:e].copy()
            out[out != 0] = 3
            return out.astype(int)

    # Fallback
    s, e, _, _ = band_info[0]
    out = grid[s:e].copy()
    out[out != 0] = 3
    return out.astype(int)

