def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid[grid != 0], return_counts=True)
    if len(vals) == 0:
        return grid.copy()

    # Find the unique nonzero color used by the special tile
    color = vals[np.argmin(counts)]

    # Determine tile height by finding the first all-zero horizontal separator
    row_nonzero = np.any(grid != 0, axis=1)
    zero_runs = []
    start = None
    for i, nz in enumerate(row_nonzero):
        if not nz and start is None:
            start = i
        elif nz and start is not None:
            zero_runs.append((start, i))
            start = None
    if start is not None:
        zero_runs.append((start, len(row_nonzero)))

    # Tile height is the smallest non-empty block of nonzero rows between zero bands
    blocks = []
    prev = 0
    for s, e in zero_runs:
        if prev < s:
            blocks.append((prev, s))
        prev = e
    if prev < len(row_nonzero):
        blocks.append((prev, len(row_nonzero)))
    blocks = [b for b in blocks if np.any(row_nonzero[b[0]:b[1]])]
    tile_h = min((b[1] - b[0] for b in blocks), default=grid.shape[0])

    # Determine tile width by finding the first all-zero vertical separator
    col_nonzero = np.any(grid != 0, axis=0)
    zero_runs = []
    start = None
    for i, nz in enumerate(col_nonzero):
        if not nz and start is None:
            start = i
        elif nz and start is not None:
            zero_runs.append((start, i))
            start = None
    if start is not None:
        zero_runs.append((start, len(col_nonzero)))

    blocks = []
    prev = 0
    for s, e in zero_runs:
        if prev < s:
            blocks.append((prev, s))
        prev = e
    if prev < len(col_nonzero):
        blocks.append((prev, len(col_nonzero)))
    blocks = [b for b in blocks if np.any(col_nonzero[b[0]:b[1]])]
    tile_w = min((b[1] - b[0] for b in blocks), default=grid.shape[1])

    # Find the tile containing the unique color
    r0 = c0 = 0
    found = False
    for r in range(0, grid.shape[0] - tile_h + 1):
        for c in range(0, grid.shape[1] - tile_w + 1):
            tile = grid[r:r + tile_h, c:c + tile_w]
            nz = tile[tile != 0]
            if nz.size > 0 and np.all(nz == color):
                r0, c0 = r, c
                found = True
                break
        if found:
            break

    out = grid[r0:r0 + tile_h, c0:c0 + tile_w].copy()
    out[out != 0] = 3
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid[grid != 0], return_counts=True)
    if len(vals) == 0:
        return grid.copy()

    # Find the unique nonzero color used by exactly one connected nonzero block
    # by detecting maximal rectangular tile regions separated by zero bands.
    h, w = grid.shape

    def zero_runs(arr):
        runs = []
        i = 0
        n = len(arr)
        while i < n:
            if arr[i] == 0:
                j = i
                while j < n and arr[j] == 0:
                    j += 1
                runs.append((i, j))
                i = j
            else:
                i += 1
        return runs

    row_zero = np.all(grid == 0, axis=1)
    col_zero = np.all(grid == 0, axis=0)

    row_runs = zero_runs(row_zero.astype(int))
    col_runs = zero_runs(col_zero.astype(int))

    row_bounds = []
    start = 0
    for a, b in row_runs:
        if start < a:
            row_bounds.append((start, a))
        start = b
    if start < h:
        row_bounds.append((start, h))

    col_bounds = []
    start = 0
    for a, b in col_runs:
        if start < a:
            col_bounds.append((start, a))
        start = b
    if start < w:
        col_bounds.append((start, w))

    # Choose the tile whose nonzero cells are all the same color and that color is unique globally.
    best = None
    for r0, r1 in row_bounds:
        for c0, c1 in col_bounds:
            tile = grid[r0:r1, c0:c1]
            nz = tile[tile != 0]
            if nz.size == 0:
                continue
            u = np.unique(nz)
            if len(u) == 1:
                color = int(u[0])
                if np.sum(grid == color) == nz.size:
                    best = tile
                    break
        if best is not None:
            break

    if best is None:
        # Fallback: use the color with smallest count among nonzero colors
        color = int(vals[np.argmin(counts)])
        positions = np.argwhere(grid == color)
        r0, c0 = positions.min(axis=0)
        r1, c1 = positions.max(axis=0) + 1
        best = grid[r0:r1, c0:c1]

    out = (best != 0).astype(int) * 3
    return out

