import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    def score_period(arr, p):
        if p <= 0:
            return -1
        ok = 0
        total = 0
        for i in range(len(arr)):
            j = i % p
            if arr[i] != 0:
                total += 1
                if arr[i] == arr[j]:
                    ok += 1
        return ok, total

    def best_period_1d(arr):
        n = len(arr)
        best_p = 1
        best_ratio = (-1, -1)
        for p in range(1, n + 1):
            ok, total = score_period(arr, p)
            ratio = (ok, total)
            if ratio > best_ratio:
                best_ratio = ratio
                best_p = p
        return best_p

    row_period = best_period_1d(g[0])
    col_period = best_period_1d(g[:, 0])

    # Refine by checking all rows/cols and choosing smallest consistent period
    def period_consistency_rows(p):
        ok = 0
        total = 0
        for r in range(h):
            for c in range(w):
                v = g[r, c]
                if v != 0:
                    total += 1
                    if v == g[r, c % p]:
                        ok += 1
        return ok, total

    def period_consistency_cols(p):
        ok = 0
        total = 0
        for r in range(h):
            for c in range(w):
                v = g[r, c]
                if v != 0:
                    total += 1
                    if v == g[r % p, c]:
                        ok += 1
        return ok, total

    best_rp = 1
    best_rc = (-1, -1)
    for p in range(1, w + 1):
        sc = period_consistency_rows(p)
        if sc > best_rc:
            best_rc = sc
            best_rp = p

    best_cp = 1
    best_cc = (-1, -1)
    for p in range(1, h + 1):
        sc = period_consistency_cols(p)
        if sc > best_cc:
            best_cc = sc
            best_cp = p

    row_period = best_rp
    col_period = best_cp

    # Build candidate tile from nonzero entries using periodic projection
    tile = np.zeros((col_period, row_period), dtype=g.dtype)
    counts = np.zeros((col_period, row_period), dtype=int)

    for r in range(h):
        for c in range(w):
            v = g[r, c]
            if v != 0:
                rr = r % col_period
                cc = c % row_period
                tile[rr, cc] = v
                counts[rr, cc] += 1

    # If some tile cells remain zero, infer from any matching nonzero row/col pattern
    for rr in range(col_period):
        for cc in range(row_period):
            if counts[rr, cc] == 0:
                vals = []
                for r in range(rr, h, col_period):
                    for c in range(cc, w, row_period):
                        v = g[r, c]
                        if v != 0:
                            vals.append(v)
                if vals:
                    tile[rr, cc] = vals[0]

    out = np.zeros_like(g)
    for r in range(h):
        for c in range(w):
            out[r, c] = tile[r % col_period, c % row_period]
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    def row_period(row):
        for p in range(1, w + 1):
            ok = True
            for j in range(w):
                v = row[j]
                if v != 0 and v != row[j % p]:
                    ok = False
                    break
            if ok:
                return p
        return w

    def col_period(col):
        for p in range(1, h + 1):
            ok = True
            for i in range(h):
                v = col[i]
                if v != 0 and v != col[i % p]:
                    ok = False
                    break
            if ok:
                return p
        return h

    rp = min(row_period(g[i]) for i in range(h))
    cp = min(col_period(g[:, j]) for j in range(w))

    tile = np.zeros((cp, rp), dtype=g.dtype)
    for i in range(h):
        for j in range(w):
            v = g[i, j]
            if v != 0:
                tile[i % cp, j % rp] = v

    out = np.empty_like(g)
    for i in range(h):
        for j in range(w):
            out[i, j] = tile[i % cp, j % rp]
    return out

