def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    # Find smallest repeating row period
    row_period = h
    for p in range(1, h + 1):
        ok = True
        for i in range(h):
            if not np.array_equal(g[i], g[i % p]):
                ok = False
                break
        if ok:
            row_period = p
            break

    # Find smallest repeating column period
    col_period = w
    for p in range(1, w + 1):
        ok = True
        for j in range(w):
            if not np.array_equal(g[:, j], g[:, j % p]):
                ok = False
                break
        if ok:
            col_period = p
            break

    # Reconstruct the base tile using non-zero cells
    base = np.zeros((row_period, col_period), dtype=g.dtype)
    for i in range(h):
        for j in range(w):
            v = g[i, j]
            if v != 0:
                base[i % row_period, j % col_period] = v

    # Fill zeros from the periodic lattice
    out = np.empty_like(g)
    for i in range(h):
        for j in range(w):
            out[i, j] = base[i % row_period, j % col_period]
    return out

