def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    # Find smallest repeating period in rows and columns using non-zero evidence.
    def infer_period_line(arr, axis=0):
        n = arr.shape[axis]
        vals = []
        for i in range(n):
            if axis == 0:
                line = arr[i, :]
            else:
                line = arr[:, i]
            vals.append(tuple(line.tolist()))
        # candidate periods
        for p in range(1, n + 1):
            ok = True
            for i in range(n):
                a = vals[i]
                b = vals[i % p]
                # compare only where both are non-zero
                for x, y in zip(a, b):
                    if x != 0 and y != 0 and x != y:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                return p
        return n

    rp = infer_period_line(g, axis=0)
    cp = infer_period_line(g, axis=1)

    # Build template by taking the first compatible non-zero value for each residue class.
    template = np.zeros((rp, cp), dtype=int)
    for i in range(h):
        for j in range(w):
            v = g[i, j]
            if v != 0:
                r = i % rp
                c = j % cp
                if template[r, c] == 0:
                    template[r, c] = v

    # Fill any remaining template zeros by consistency from visible cells.
    changed = True
    while changed:
        changed = False
        for i in range(h):
            for j in range(w):
                v = g[i, j]
                if v != 0:
                    r = i % rp
                    c = j % cp
                    if template[r, c] == 0:
                        template[r, c] = v
                        changed = True

    out = np.zeros_like(g)
    for i in range(h):
        for j in range(w):
            out[i, j] = template[i % rp, j % cp]
    return out

