                red_pos = np.argwhere(block == 2)[0]
                tr, tc = np.argwhere(block == target)[0]
                if red_pos[0] == tr and red_pos[1] == tc:
                    continue
                if red_pos[0] == 0 and red_pos[1] == 0:
                    start_r, start_c = r, c + 1
                    step_r, step_c = 1, -1
                elif red_pos[0] == 0 and red_pos[1] == 1:
                    start_r, start_c = r, c
                    step_r, step_c = 1, 1
                elif red_pos[0] == 1 and red_pos[1] == 0:
                    start_r, start_c = r + 1, c + 1
                    step_r, step_c = -1, -1
                else:
                    start_r, start_c = r + 1, c
                    step_r, step_c = -1, 1
                out = np.zeros_like(g)
                for k in range(max(h, w) * 2):
                    sr = start_r + k * step_r
                    sc = start_c + k * step_c
                    for t in range(k + 1):
                        rr = sr + t * (-step_c)
                        cc = sc + t * step_r
                        if 0 <= rr < h and 0 <= cc < w:
                            out[rr, cc] = target
                return out
    # Fallback: infer from any 2x2 nonzero block
    for r in range(h - 1):
        for c in range(w - 1):
            block = g[r:r+2, c:c+2]
            nzb = block[block != 0]
            if nzb.size >= 2:
                target = int(nzb[0])
                out = np.zeros_like(g)
                for k in range(max(h, w) * 2):
                    sr = r + k
                    sc = c + (1 if block[0, 0] == 2 else 0) - k
                    for t in range(k + 1):
                        rr = sr - t
                        cc = sc - (k - t)
                        if 0 <= rr < h and 0 <= cc < w:
                            out[rr, cc] = target
                return out
    return g

