def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    colors = [c for c in np.unique(grid) if c != 0]
    if len(colors) == 0:
        return np.zeros((0, 0), dtype=int)

    # Find a full horizontal divider row if present
    divider_row = None
    for r in range(grid.shape[0]):
        if np.all(grid[r] == grid[r, 0]) and grid[r, 0] != 0:
            divider_row = r
            divider_color = int(grid[r, 0])
            break

    if divider_row is not None:
        top = grid[:divider_row, :]
        bottom = grid[divider_row + 1:, :]
        # Determine block height by splitting around the divider
        h = min(top.shape[0], bottom.shape[0])
        w = min(top.shape[1], bottom.shape[1])
        top = top[-h:, :w]
        bottom = bottom[:h, :w]

        # If blocks are larger than 4x4, find the minimal bounding boxes of nonzero cells
        def bbox(arr):
            pts = np.argwhere(arr != 0)
            if pts.size == 0:
                return (0, 0, arr.shape[0], arr.shape[1])
            r0, c0 = pts.min(axis=0)
            r1, c1 = pts.max(axis=0) + 1
            return r0, c0, r1, c1

        tr0, tc0, tr1, tc1 = bbox(top)
        br0, bc0, br1, bc1 = bbox(bottom)
        top = top[tr0:tr1, tc0:tc1]
        bottom = bottom[br0:br1, bc0:bc1]

        h = min(top.shape[0], bottom.shape[0])
        w = min(top.shape[1], bottom.shape[1])
        top = top[:h, :w]
        bottom = bottom[:h, :w]

        out = np.zeros((h, w), dtype=int)

        # Connected component sizes in each block for each color
        def comp_sizes(arr):
            sizes = {}
            visited = np.zeros(arr.shape, dtype=bool)
            H, W = arr.shape
            for r in range(H):
                for c in range(W):
                    if arr[r, c] == 0 or visited[r, c]:
                        continue
                    col = int(arr[r, c])
                    stack = [(r, c)]
                    visited[r, c] = True
                    cnt = 0
                    while stack:
                        x, y = stack.pop()
                        cnt += 1
                        for dx, dy in ((1,0), (-1,0), (0,1), (0,-1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < H and 0 <= ny < W and not visited[nx, ny] and arr[nx, ny] == col:
                                visited[nx, ny] = True
                                stack.append((nx, ny))
                    sizes[col] = max(sizes.get(col, 0), cnt)
            return sizes

        top_sizes = comp_sizes(top)
        bottom_sizes = comp_sizes(bottom)

        for r in range(h):
            for c in range(w):
                a = int(top[r, c])
                b = int(bottom[r, c])
                if a == b:
                    out[r, c] = 0
                elif a == 0 and b != 0:
                    out[r, c] = b
                elif b == 0 and a != 0:
                    out[r, c] = a
                else:
                    sa = top_sizes.get(a, 0)
                    sb = bottom_sizes.get(b, 0)
                    if sa > sb:
                        out[r, c] = a
                    elif sb > sa:
                        out[r, c] = b
                    else:
                        out[r, c] = a
        return out

    # Fallback: return bounding box of nonzero cells
    pts = np.argwhere(grid != 0)
    if pts.size == 0:
        return np.zeros((0, 0), dtype=int)
    r0, c0 = pts.min(axis=0)
    r1, c1 = pts.max(axis=0) + 1
    return grid[r0:r1, c0:c1]

