                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < H and 0 <= ny < W and not visited[nx, ny] and block[nx, ny] == val:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                sizes[val] = max(sizes.get(val, 0), count)
        return sizes

    top_sizes = cluster_sizes(top)
    bottom_sizes = cluster_sizes(bottom)

    out = np.zeros((h, w), dtype=int)
    for r in range(h):
        for c in range(w):
            a = top[r, c]
            b = bottom[r, c]
            if a == b:
                out[r, c] = 0
            elif a == 0 and b != 0:
