def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    colors = [c for c in np.unique(grid) if c != 0]

    # Find separator row if present: a row with many same nonzero cells and no other colors
    sep_row = None
    for r in range(grid.shape[0]):
        vals = grid[r]
        nz = vals[vals != 0]
        if len(nz) > 0 and np.all(nz == nz[0]) and len(nz) >= grid.shape[1] // 2:
            sep_row = r
            break

    if sep_row is not None:
        top = grid[:sep_row]
        bottom = grid[sep_row + 1:]
        regions = [top, bottom]
    else:
        regions = [grid]

    def components(mask):
        h, w = mask.shape
        seen = np.zeros_like(mask, dtype=bool)
        comps = []
        for i in range(h):
            for j in range(w):
                if mask[i, j] and not seen[i, j]:
                    stack = [(i, j)]
                    seen[i, j] = True
                    comp = []
                    while stack:
                        x, y = stack.pop()
                        comp.append((x, y))
                        for dx, dy in ((1,0), (-1,0), (0,1), (0,-1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < h and 0 <= ny < w and mask[nx, ny] and not seen[nx, ny]:
                                seen[nx, ny] = True
                                stack.append((nx, ny))
                    comps.append(comp)
        return comps

    # Choose region and color whose cells form one connected component
    chosen_mask = None
    for region in regions:
        if region.size == 0:
            continue
        for c in [x for x in np.unique(region) if x != 0]:
            mask = region == c
            comps = components(mask)
            if len(comps) == 1 and np.sum(mask) > 0:
                chosen_mask = mask
                break
        if chosen_mask is not None:
            break

    if chosen_mask is None:
        # Fallback: use the nonzero cells of the first region
        region = regions[0]
        colors = [x for x in np.unique(region) if x != 0]
        if not colors:
            return np.zeros((0, 0), dtype=int)
        c = colors[0]
        chosen_mask = region == c

    coords = np.argwhere(chosen_mask)
    if coords.size == 0:
        return np.zeros((0, 0), dtype=int)

    r0, c0 = coords.min(axis=0)
    r1, c1 = coords.max(axis=0)
    out = np.zeros((r1 - r0 + 1, c1 - c0 + 1), dtype=int)
    out[chosen_mask[r0:r1 + 1, c0:c1 + 1]] = 3
    return out

