def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid, return_counts=True)
    nonzero = [(v, c) for v, c in zip(vals, counts) if v != 0]
    if not nonzero:
        return grid.copy()

    # Find the separator color: the one that appears in a solid row/column-like band
    # and is not part of the target 4x4 pattern. In the provided tasks this is 3 or 4.
    sep_color = None
    for v, c in nonzero:
        if np.any(np.all(grid == v, axis=1)) or np.any(np.all(grid == v, axis=0)):
            sep_color = v
            break

    if sep_color is None:
        sep_color = max(nonzero, key=lambda x: x[1])[0]

    # Extract connected components for each non-separator color
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    def neighbors(r, c):
        if r > 0:
            yield r - 1, c
        if r + 1 < h:
            yield r + 1, c
        if c > 0:
            yield r, c - 1
        if c + 1 < w:
            yield r, c + 1

    components = []
    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 or grid[r, c] == sep_color or visited[r, c]:
                continue
            color = grid[r, c]
            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for nx, ny in neighbors(x, y):
                    if not visited[nx, ny] and grid[nx, ny] == color:
                        visited[nx, ny] = True
                        stack.append((nx, ny))
            components.append((color, cells))

    if not components:
        return np.zeros((4, 3), dtype=int)

    # The target is the clustered color: the one whose component is the most compact
    # and forms a single connected shape in its local 4x4 region.
    def comp_score(item):
        color, cells = item
        rs = [p[0] for p in cells]
        cs = [p[1] for p in cells]
        area = (max(rs) - min(rs) + 1) * (max(cs) - min(cs) + 1)
        return (len(cells), -area)

    target_color, target_cells = max(components, key=comp_score)

    rs = [p[0] for p in target_cells]
    cs = [p[1] for p in target_cells]
    r0, r1 = min(rs), max(rs)
    c0, c1 = min(cs), max(cs)

    # Normalize to a 4x4 output by taking the bounding box of the clustered shape.
    # If the box is larger than 4x4, crop; if smaller, place into top-left of 4x4.
    out = np.zeros((4, 4), dtype=int)
    for r, c in target_cells:
        rr = r - r0
        cc = c - c0
        if 0 <= rr < 4 and 0 <= cc < 4:
            out[rr, cc] = 3

    return out

