def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    colors = [c for c in np.unique(grid) if c != 0 and c != 4]
    if not colors:
        return np.zeros((4, 4), dtype=int)

    best = None
    best_score = None

    for color in colors:
        coords = np.argwhere(grid == color)
        if coords.size == 0:
            continue
        r0, c0 = coords.min(axis=0)
        r1, c1 = coords.max(axis=0)
        h = r1 - r0 + 1
        w = c1 - c0 + 1
        if h != 4 or w != 4:
            continue
        sub = (grid[r0:r1 + 1, c0:c1 + 1] == color).astype(int)
        count = int(sub.sum())
        bbox_area = 16
        score = (count, -bbox_area)
        if best is None or score > best_score:
            best = sub
            best_score = score

    if best is None:
        # Fallback: choose the 4x4 bounding box of the densest color component
        for color in colors:
            coords = np.argwhere(grid == color)
            if coords.size == 0:
                continue
            r0, c0 = coords.min(axis=0)
            r1, c1 = coords.max(axis=0)
            if r1 - r0 + 1 >= 4 and c1 - c0 + 1 >= 4:
                sub = (grid[r0:r0 + 4, c0:c0 + 4] == color).astype(int)
                count = int(sub.sum())
                score = (count, -abs(count - 6))
                if best is None or score > best_score:
                    best = sub
                    best_score = score

    if best is None:
        best = np.zeros((4, 4), dtype=int)

    return np.where(best > 0, 3, 0).astype(int)

