        return [vals[i] - vals[i - 1] for i in range(1, len(vals)) if vals[i] - vals[i - 1] > 0]

    d = 0
    for x in diffs(row_changes) + diffs(col_changes):
        d = x if d == 0 else gcd(d, x)

