    out = np.zeros_like(g)

    nz = np.argwhere(g != 0)
    if nz.size == 0:
        return out

    # Find the anchor cell: the unique nonzero cell that lies on a row/column
    # with other nonzero cells, or the cell that is part of the visible motif center.
    # We choose the cell minimizing total Manhattan distance to other nonzero cells
    # among cells that share row/col with at least one other nonzero cell.
    candidates = []
    for r, c in nz:
        same_row = np.any((nz[:, 0] == r) & (nz[:, 1] != c))
        same_col = np.any((nz[:, 1] == c) & (nz[:, 0] != r))
        if same_row or same_col:
            d = np.sum(np.abs(nz[:, 0] - r) + np.abs(nz[:, 1] - c))
            candidates.append((d, r, c))
    if candidates:
        _, ar, ac = min(candidates)
    else:
        ar, ac = nz[0]

    # Collect visible colors on the anchor row and column, excluding the anchor.
    row_cells = [(c, g[ar, c]) for c in range(w) if g[ar, c] != 0 and c != ac]
    col_cells = [(r, g[r, ac]) for r in range(h) if g[r, ac] != 0 and r != ar]

    # Determine repeating sequences.
    row_cells.sort()
    col_cells.sort()

    row_colors = [v for _, v in row_cells]
    col_colors = [v for _, v in col_cells]

    # If one axis has only the anchor, infer from the other axis.
